  'testimonials.t2': { en:'As a founding member, you get direct access to the founder. Your feedback shapes the product roadmap. Features you need get built first.', nl:'Als founding member krijgt u directe toegang tot de oprichter. Uw feedback bepaalt de productroadmap. Functies die u nodig heeft worden eerst gebouwd.', fr:'En tant que membre fondateur, vous avez un acc\u00e8s direct au fondateur. Vos retours fa\u00e7onnent la feuille de route produit.', de:'Als Gr\u00fcndungsmitglied erhalten Sie direkten Zugang zum Gr\u00fcnder. Ihr Feedback bestimmt die Produkt-Roadmap.', es:'Como miembro fundador, tiene acceso directo al fundador. Sus comentarios definen la hoja de ruta del producto.' },
  'testimonials.n2': { en:'Direct Founder Access', nl:'Directe toegang tot de oprichter', fr:'Acc\u00e8s direct au fondateur', de:'Direkter Zugang zum Gr\u00fcnder', es:'Acceso directo al fundador' },
