  'sub.billingP2': { en:'You can cancel anytime from this page. If you cancel, your access continues until the end of your current billing period.', nl:'U kunt op elk moment opzeggen via deze pagina. Bij opzegging behoudt u toegang tot het einde van uw huidige factureringsperiode.', fr:'Vous pouvez annuler à tout moment depuis cette page. Si vous annulez, votre accès continue jusqu\'à la fin de votre période de facturation en cours.', de:'Sie können jederzeit von dieser Seite aus kündigen. Bei Kündigung bleibt Ihr Zugang bis zum Ende der aktuellen Abrechnungsperiode bestehen.', es:'Puede cancelar en cualquier momento desde esta página. Si cancela, su acceso continúa hasta el final de su período de facturación actual.' },
  'sub.billingP3': { en:'All payments are processed securely by Stripe. FirmFlow never sees or stores your card details.', nl:'Alle betalingen worden veilig verwerkt door Stripe. FirmFlow ziet of bewaart uw kaartgegevens nooit.', fr:'Tous les paiements sont traités en toute sécurité par Stripe. FirmFlow ne voit ni ne stocke vos coordonnées bancaires.', de:'Alle Zahlungen werden sicher über Stripe abgewickelt. FirmFlow sieht oder speichert Ihre Kartendaten niemals.', es:'Todos los pagos se procesan de forma segura por Stripe. FirmFlow nunca ve ni almacena los datos de su tarjeta.' },
  'sub.questions': { en:'Questions? Email us at', nl:'Vragen? E-mail ons op', fr:'Questions ? Écrivez-nous à', de:'Fragen? Schreiben Sie uns an', es:'¿Preguntas? Envíenos un correo a' },

