  'home.comp.title': { en:'Why firms switch to FirmFlow', nl:'Waarom kantoren overstappen naar FirmFlow', fr:'Pourquoi les cabinets passent à FirmFlow', de:'Warum Kanzleien zu FirmFlow wechseln', es:'Por qué las firmas cambian a FirmFlow' },
  'home.comp.subtitle': { en:'One flat price. All the features. No surprises.', nl:'Eén vaste prijs. Alle functies. Geen verrassingen.', fr:'Un prix fixe. Toutes les fonctionnalités. Aucune surprise.', de:'Ein Festpreis. Alle Funktionen. Keine Überraschungen.', es:'Un precio fijo. Todas las funciones. Sin sorpresas.' },
