  'con.f8.title': { en:'Multi-currency for global clients', nl:'Multi-valuta voor wereldwijde klanten', fr:'Multi-devises pour clients internationaux', de:'Mehrwährung für globale Kunden', es:'Multi-moneda para clientes globales' },
  'con.f8.desc': { en:'Invoice in EUR, GBP, USD, CHF, and other currencies. Perfect for consultancies with international clients.', nl:'Factureer in EUR, GBP, USD, CHF en andere valuta. Perfect voor adviesbureaus met internationale klanten.', fr:'Facturez en EUR, GBP, USD, CHF et autres devises. Parfait pour les cabinets avec clients internationaux.', de:'Rechnung in EUR, GBP, USD, CHF und anderen Währungen. Perfekt für Beratungen mit internationalen Kunden.', es:'Facture en EUR, GBP, USD, CHF y otras monedas. Perfecto para consultorías con clientes internacionales.' },
